#include<bits/stdc++.h>
using namespace std;
int a[100010],b[100010];
const int mod=1e8-3;
long long ans;
struct node
{
	int val,id;
	bool operator<(const node&b)const
	{
		return val<b.val;
	}
}x[100010],y[100010];
void msort(int l,int r)
{
	if(l>=r)
	{
		return;
	}
	int mid=(l+r)/2;
	msort(l,mid);
	msort(mid+1,r);
	int i=l,j=mid+1,tot=l;
	while(i<=mid&&j<=r)
	{
		if(b[i]<=b[j])
		{
			a[tot++]=b[i++];
		}
		else
		{
			a[tot++]=b[j++];
			ans+=mid-i+1;
			ans%=mod;
		}
	}
	while(i<=mid)
	{
		a[tot++]=b[i++];
	}
	while(j<=r)
	{
		a[tot++]=b[j++];
	}
	for(int k=l;k<=r;k++)
	{
		b[k]=a[k];
	}
}
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&x[i].val);
	}
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&y[i].val);
		x[i].id=y[i].id=i;
	}
	sort(x+1,x+1+n);
	sort(y+1,y+1+n);
	for(int i=1;i<=n;i++)
	{
		b[y[i].id]=x[i].id;
	}
	msort(1,n);
	printf("%lld",ans);
	return 0;
}
